// Flatten every adapter's new_rfp_ids into one item per id.
const out = [];
for (const item of items) {
  const body = item.json || {};
  const adapters = body.adapters || [];
  for (const a of adapters) {
    for (const rid of (a.new_rfp_ids || [])) {
      out.push({ json: { rfp_id: rid, adapter_name: a.adapter_name, adapter_type: a.adapter_type } });
    }
  }
}
return out;

// Build a rich Slack Block Kit payload with source breadcrumb (supplemental 4.B).
const raw = $json;
const rfp = raw.rfp || {};
const screening = raw.screening || {};
const sourceType = rfp.source_type || 'unknown';
const meta = rfp.source_metadata || {};
const sender = meta.from || meta.notice_id || meta.filename || meta.url || '';
const received = rfp.received_at ? new Date(rfp.received_at).toLocaleString() : '';
const breadcrumb = sourceType === 'email'
  ? `Source: email from ${sender} (received ${received})`
  : sourceType === 'sam_gov'
    ? `Source: SAM.gov notice ${meta.notice_id || rfp.external_id || ''} (received ${received})`
    : `Source: ${sourceType} ${sender} (received ${received})`;

const rationale = screening.rationale || {};
const dims = (rationale.dimensions || []).slice(0).sort((a,b) => (b.weight*b.score/100) - (a.weight*a.score/100));
const topTwo = dims.slice(0, 2).map(d => `• *${d.name}* — score ${d.score} (weight ${d.weight}): ${(d.reasoning || '').slice(0, 160)}`).join('\n');

const uiUrl = $env.KAIZEN_UI_URL || 'http://localhost:8501';
const reviewUrl = `${uiUrl}/?rfp=${rfp.id}`;

const recommendation = screening.recommendation || 'unknown';
const recEmoji = { pursue: ':white_check_mark:', maybe: ':grey_question:', skip: ':no_entry:' }[recommendation] || ':grey_question:';

const payload = {
  text: `RFP screened: ${rfp.title || '(no title)'} — ${recEmoji} ${recommendation} (score ${screening.fit_score})`,
  blocks: [
    {
      type: 'header',
      text: { type: 'plain_text', text: `${recEmoji} ${rfp.title || '(no title)'}`, emoji: true }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Agency*\n${rfp.agency || '—'}` },
        { type: 'mrkdwn', text: `*Fit score*\n${screening.fit_score ?? '—'}` },
        { type: 'mrkdwn', text: `*Recommendation*\n${recommendation}` },
        { type: 'mrkdwn', text: `*Effort*\n${screening.effort_estimate || '—'}` }
      ]
    },
    { type: 'context', elements: [ { type: 'mrkdwn', text: breadcrumb } ] },
    { type: 'section', text: { type: 'mrkdwn', text: `*Top reasons*\n${topTwo || '_none surfaced_'}` } },
    {
      type: 'actions',
      elements: [
        { type: 'button', text: { type: 'plain_text', text: 'Review in dashboard' }, url: reviewUrl, style: 'primary' },
        { type: 'button', text: { type: 'plain_text', text: 'Dismiss' }, value: `dismiss_${rfp.id}` }
      ]
    }
  ]
};
return [{ json: payload }];
